<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const salario=parseFloat(document.getElementById('inss-salario').value);clearError();if(isNaN(salario)||salario<=0){showError('Informe um salário bruto válido maior que zero.');return;}let aliquota=0.075;if(salario>1412&&salario<=2666.68){aliquota=0.09;}else if(salario>2666.68&&salario<=4000.03){aliquota=0.12;}else if(salario>4000.03){aliquota=0.14;}const desconto=salario*aliquota;document.getElementById('inss-desconto').textContent='R$ '+fmtBRL(desconto);document.getElementById('inss-aliquota').textContent=fmtNum(aliquota*100,2)+'%';document.getElementById('tool-detail').textContent='Estimativa simplificada com base em faixas previdenciárias.';showResult('tool-result');}function clearTool(){document.getElementById('inss-salario').value='';['inss-desconto','inss-aliquota'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule o INSS antes de copiar o resultado.');return;}copyToClipboard('INSS estimado: '+document.getElementById('inss-desconto').textContent,button);}
</script>
<?php ns_render_page_end(); ?>

